.sig-neumorphism-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(255,255,255,0.72);
  border-radius: 24px;
  background: linear-gradient(145deg, #e6ece8, #dce5e0);
  color: #243033;
  box-shadow: 12px 12px 28px rgba(72,84,87,0.20), -12px -12px 28px rgba(255,255,255,0.84);
  font-family: Inter, ui-sans-serif, system-ui, sans-serif;
}
.sig-neumorphism-hero::before { content: ""; position: absolute; inset: 0; background: linear-gradient(145deg, rgba(255,255,255,0.48), rgba(82,111,123,0.08)); background-size: auto; opacity: 0.78; pointer-events: none; }
.sig-neumorphism-hero > * { position: relative; z-index: 1; }
.sig-neumorphism-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-neumorphism-hero .kicker { width: fit-content; border: 1px solid rgba(255,255,255,0.72); border-radius: 999px; padding: 6px 10px; color: #526f7b; background: #dce5e0; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-neumorphism-hero h1 { margin: 0; max-width: 620px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-neumorphism-hero p { margin: 0; max-width: 560px; color: #6b777a; font-size: 15px; line-height: 1.78; }
.sig-neumorphism-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-neumorphism-hero button { height: 40px; padding: 0 16px; border-radius: calc(24px / 2 + 4px); border: 1px solid rgba(255,255,255,0.72); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-neumorphism-hero .primary { background: #526f7b; color: #ffffff; border-color: #526f7b; }
.sig-neumorphism-hero .secondary { background: transparent; color: #243033; }
.sig-neumorphism-hero button:hover { transform: translateY(-1px); border-color: #526f7b; }
.sig-neumorphism-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(255,255,255,0.72); border-radius: calc(24px - 2px); background: #dce5e0; backdrop-filter: blur(18px) saturate(140%); }
.sig-neumorphism-hero .artifact h2 { margin: 0; font-size: 13px; color: #526f7b; text-transform: uppercase; letter-spacing: 0; }
.sig-neumorphism-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-neumorphism-hero .metric { padding: 14px; border: 1px solid rgba(255,255,255,0.72); border-radius: calc(24px - 4px); background: color-mix(in srgb, #e6ece8 76%, transparent); }
.sig-neumorphism-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-neumorphism-hero .metric span { display: block; margin-top: 6px; color: #6b777a; font-size: 11px; }
.sig-neumorphism-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #526f7b, #9b7c33); }
@media (max-width: 780px) { .sig-neumorphism-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-neumorphism-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(255,255,255,0.72); border-radius: 24px; background: #e6ece8; color: #243033; box-shadow: 12px 12px 28px rgba(72,84,87,0.20), -12px -12px 28px rgba(255,255,255,0.84); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-neumorphism-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-neumorphism-card .label { color: #526f7b; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-neumorphism-card .pill { border: 1px solid rgba(255,255,255,0.72); border-radius: 999px; padding: 5px 9px; color: #6b777a; background: #dce5e0; font-size: 11px; }
.sig-neumorphism-card h3 { margin: 0 0 10px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-neumorphism-card p { margin: 0; color: #6b777a; font-size: 13px; line-height: 1.7; }
.sig-neumorphism-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(255,255,255,0.72); }
.sig-neumorphism-card .strip strong { font-variant-numeric: tabular-nums; color: #243033; }
.sig-neumorphism-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(24px - 4px); background: #526f7b; color: #ffffff; font-weight: 900; }

.sig-neumorphism-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(255,255,255,0.72); border-radius: 24px; background: #e6ece8; color: #243033; box-shadow: 12px 12px 28px rgba(72,84,87,0.20), -12px -12px 28px rgba(255,255,255,0.84); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-neumorphism-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-neumorphism-nav .mark { width: 30px; height: 30px; border-radius: calc(24px - 4px); background: linear-gradient(135deg, #526f7b, #9b7c33); box-shadow: inset 0 0 0 1px rgba(255,255,255,0.72); }
.sig-neumorphism-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-neumorphism-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(24px - 6px); color: #6b777a; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-neumorphism-nav a:hover, .sig-neumorphism-nav a.active { color: #243033; background: #dce5e0; }
.sig-neumorphism-nav button { height: 34px; padding: 0 13px; border-radius: calc(24px - 6px); border: 1px solid #526f7b; background: #526f7b; color: #ffffff; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-neumorphism-nav { align-items: stretch; flex-direction: column; } }

.sig-neumorphism-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(255,255,255,0.72); border-radius: 24px; background: #e6ece8; color: #243033; box-shadow: 12px 12px 28px rgba(72,84,87,0.20), -12px -12px 28px rgba(255,255,255,0.84); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-neumorphism-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #243033; }
.sig-neumorphism-form small { color: #6b777a; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-neumorphism-form .row { display: flex; gap: 10px; }
.sig-neumorphism-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(24px - 6px); border: 1px solid rgba(255,255,255,0.72); background: #dce5e0; color: #243033; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-neumorphism-form input:focus { border-color: #526f7b; box-shadow: 0 0 0 3px color-mix(in srgb, #526f7b 18%, transparent); }
.sig-neumorphism-form button { height: 42px; padding: 0 14px; border-radius: calc(24px - 6px); border: 1px solid #526f7b; background: #526f7b; color: #ffffff; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-neumorphism-form .row { flex-direction: column; } }

.sig-neumorphism-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(255,255,255,0.72); border-radius: 24px; background: #e6ece8; color: #243033; box-shadow: 12px 12px 28px rgba(72,84,87,0.20), -12px -12px 28px rgba(255,255,255,0.84); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-neumorphism-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-neumorphism-table th, .sig-neumorphism-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(255,255,255,0.72); }
.sig-neumorphism-table th { color: #6b777a; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: #dce5e0; }
.sig-neumorphism-table td { color: #243033; }
.sig-neumorphism-table tr:last-child td { border-bottom: 0; }
.sig-neumorphism-table tbody tr:hover td { background: #dce5e0; }
.sig-neumorphism-table .mono { font-variant-numeric: tabular-nums; }
.sig-neumorphism-table .status { display: inline-flex; align-items: center; gap: 6px; color: #526f7b; font-weight: 800; }
.sig-neumorphism-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #526f7b; }

.btn-clay {
  padding: 14px 28px;
  background: #e8ecf0;
  color: #5a6170;
  font-family: 'Inter', system-ui;
  font-size: 14px;
  font-weight: 500;
  border: none;
  border-radius: 14px;
  cursor: pointer;
  box-shadow: 6px 6px 12px #c5cad1, -6px -6px 12px #ffffff;
  transition: all 0.15s;
}
.btn-clay:hover {
  box-shadow: 4px 4px 8px #c5cad1, -4px -4px 8px #ffffff;
}
.btn-clay:active {
  box-shadow: inset 4px 4px 8px #c5cad1, inset -4px -4px 8px #ffffff;
}

.card-neumorph {
  width: 160px;
  padding: 24px 20px;
  background: #e8ecf0;
  border-radius: 20px;
  box-shadow: 8px 8px 16px #c5cad1, -8px -8px 16px #ffffff;
  text-align: center;
}
.card-neumorph .icon { font-size: 28px; margin-bottom: 12px; }
.card-neumorph .value {
  font-family: 'Inter', system-ui;
  font-size: 24px;
  font-weight: 700;
  color: #2d3748;
  margin-bottom: 4px;
}
.card-neumorph .label {
  font-family: 'Inter', system-ui;
  font-size: 12px;
  color: #7a8599;
}
